@@ -117,6 +117,10 @@ simdjson_inline simdjson_result<size_t> array::count_elements() & noexcept {
 }
 SIMDJSON_POP_DISABLE_WARNINGS

+simdjson_inline simdjson_result<size_t> array::size() & noexcept {
+  return count_elements();
+}
+
 simdjson_inline simdjson_result<bool> array::is_empty() & noexcept {
   bool is_not_empty;
   auto error = iter.reset_array().get(is_not_empty);
@@ -273,6 +277,10 @@ simdjson_inline  simdjson_result<size_t> simdjson_result<SIMDJSON_IMPLEMENTATION
   if (error()) { return error(); }
   return first.count_elements();
 }
+simdjson_inline  simdjson_result<size_t> simdjson_result<SIMDJSON_IMPLEMENTATION::ondemand::array>::size() & noexcept {
+  if (error()) { return error(); }
+  return first.size();
+}
 simdjson_inline  simdjson_result<bool> simdjson_result<SIMDJSON_IMPLEMENTATION::ondemand::array>::is_empty() & noexcept  {
   if (error()) { return error(); }
   return first.is_empty();
diff --git a/include/simdjson/generic/ondemand/array.h b/include/simdjson/generic/ondemand/array.h
index 7abd5fa..6cda6fd 100644
--- a/include/simdjson/generic/ondemand/array.h
+++ b/include/simdjson/generic/ondemand/array.h
@@ -52,6 +52,17 @@ public:
    * the is_empty() method.
    */
   simdjson_inline simdjson_result<size_t> count_elements() & noexcept;
+  /**
+   * This method is an alias for count_elements() provided for API symmetry with dom::array.
+   * It scans the array and counts the number of elements with O(n) complexity.
+   * The method should be called before you have begun iterating through the array.
+   * After calling this function, if successful, the array is 'rewinded' at its
+   * beginning as if it had never been accessed. If the JSON is malformed, an error
+   * is returned.
+   *
+   * To check that an array is empty, it is more performant to use the is_empty() method.
+   */
+  simdjson_inline simdjson_result<size_t> size() & noexcept;
   /**
    * This method scans the beginning of the array and checks whether the
    * array is empty.
@@ -244,6 +255,7 @@ public:
   simdjson_inline simdjson_result<SIMDJSON_IMPLEMENTATION::ondemand::array_iterator> begin() noexcept;
   simdjson_inline simdjson_result<SIMDJSON_IMPLEMENTATION::ondemand::array_iterator> end() noexcept;
   inline simdjson_result<size_t> count_elements() & noexcept;
+  inline simdjson_result<size_t> size() & noexcept;
   inline simdjson_result<bool> is_empty() & noexcept;
   inline simdjson_result<bool> reset() & noexcept;
   simdjson_inline simdjson_result<SIMDJSON_IMPLEMENTATION::ondemand::value> at(size_t index) noexcept;
